// Session affinity: ensure subsequent requests go to same machine
// This prevents "not authenticated" when load balanced across 2 machines
app.use(function(req, res, next) {
  if (req.session && req.session.userId) {
    // Pin this session to this machine instance
    res.setHeader('fly-force-instance-id', process.env.FLY_MACHINE_ID || '');
  }
  next();
});


// Pin authenticated sessions to the machine that holds the session
app.use(function(req, res, next) {
  if (req.session && req.session.userId && process.env.FLY_MACHINE_ID) {
    res.setHeader('fly-force-instance-id', req.session.machineId || process.env.FLY_MACHINE_ID);
  }
  next();
});

function requireAuth(req, res, next) {
  if (!req.session.userId) return res.status(401).json({ error: 'Not authenticated' });
  next();
}

function generateCode(len) {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  let code = '';
  for (let i = 0; i < len; i++) code += chars[Math.floor(Math.random() * chars.length)];
  return code;
}

function generateSessionCode() {
  return generateCode(3) + '-' + generateCode(3);
}

