app.post('/api/sessions', requireAuth, (req, res) => {
  const { title, candidateName, questions, candidateEmail, scheduledAt } = req.body;
  const id = uuidv4();
  let code;
  do { code = generateSessionCode(); } while (db.prepare('SELECT id FROM sessions WHERE code=?').get(code));
  db.prepare('INSERT INTO sessions (id,code,title,candidate_name,candidate_email,interviewer_id,org_id,questions,started_at,scheduled_at) VALUES (?,?,?,?,?,?,?,?,?,?)')
    .run(id, code, title || 'Interview Session', candidateName || 'Candidate', candidateEmail || null, req.session.userId, req.session.orgId, JSON.stringify(questions || []), Math.floor(Date.now() / 1000), scheduledAt || null);
  res.json({ ok: true, id, code });
});

app.get('/api/sessions', requireAuth, (req, res) => {
  const sessions = db.prepare('SELECT * FROM sessions WHERE interviewer_id=? ORDER BY created_at DESC LIMIT 100').all(req.session.userId);
  res.json(sessions.map(s => ({ ...s, flags: JSON.parse(s.flags || '[]'), questions: JSON.parse(s.questions || '[]'), trust_score: s.trust_score != null ? s.trust_score : 100, scheduled_at: s.scheduled_at || null })));
});

app.get('/api/sessions/:id', (req, res) => {
  const s = db.prepare('SELECT * FROM sessions WHERE id=?').get(req.params.id);
  if (!s) return res.json({ error: 'Session not found' });
  const flags = db.prepare('SELECT * FROM flags WHERE session_id=? ORDER BY created_at').all(req.params.id);
  res.json({ ...s, flags, questions: JSON.parse(s.questions || '[]') });
});

app.get('/api/join/:code', (req, res) => {
  const s = db.prepare('SELECT id,title,candidate_name,questions,status,code,scheduled_at FROM sessions WHERE code=?').get(req.params.code.toUpperCase());
  if (!s) return res.json({ error: 'Session not found' });
  if (s.status === 'ended') return res.json({ error: 'SESSION_ENDED' });
  if (s.scheduled_at) {
    const now = Math.floor(Date.now()/1000);
    if (now < s.scheduled_at - 300) {
      return res.json({ error: 'SESSION_SCHEDULED', scheduledAt: s.scheduled_at, title: s.title });
    }
  }
  res.json({ id:s.id, title:s.title, candidate_name:s.candidate_name, status:s.status, code:s.code, scheduled_at:s.scheduled_at||null, questions: JSON.parse(s.questions || '[]') });
});

app.patch('/api/sessions/:id', requireAuth, (req, res) => {
  const { status, trustScore, scheduledAt } = req.body;
  if (scheduledAt !== undefined) db.prepare('UPDATE sessions SET scheduled_at=? WHERE id=? AND interviewer_id=?').run(scheduledAt || null, req.params.id, req.session.userId);
  if (status) db.prepare('UPDATE sessions SET status=? WHERE id=?').run(status, req.params.id);
  if (trustScore !== undefined) db.prepare('UPDATE sessions SET trust_score=? WHERE id=?').run(trustScore, req.params.id);
  if (status === 'ended') db.prepare('UPDATE sessions SET ended_at=? WHERE id=?').run(Math.floor(Date.now() / 1000), req.params.id);
  res.json({ ok: true });
});

app.post('/api/sessions/:id/flags', (req, res) => {
  const { text, detail, severity, timeOffset } = req.body;
  const id = uuidv4();
  db.prepare('INSERT INTO flags (id,session_id,time_offset,text,detail,severity) VALUES (?,?,?,?,?,?)').run(id, req.params.id, timeOffset || '00:00', text, detail || '', severity || 'medium');
  res.json({ ok: true, id });
});

