// Allow any org member to view recordings in shared position folders
app.get('/api/recordings/:id/org-stream', requireAuth, (req, res) => {
  // Check recording is in a position folder within user's org
  const rec = db.prepare('SELECT r.* FROM recordings r LEFT JOIN job_positions p ON r.job_position_id=p.id WHERE r.id=? AND (r.interviewer_id=? OR p.org_id=?)').get(req.params.id, req.session.userId, req.session.orgId);
  if (!rec) return res.status(403).json({ error: 'Access denied' });
  const filePath = rec.file_path || path.join(DATA_DIR, 'recordings', rec.filename || '');
  if (!filePath || !fs.existsSync(filePath)) return res.status(404).json({ error: 'File not found' });
  const stat = fs.statSync(filePath);
  const range = req.headers.range;
  if (range) {
    const [startStr, endStr] = range.replace(/bytes=/, '').split('-');
    const start = parseInt(startStr, 10);
    const end = endStr ? parseInt(endStr, 10) : stat.size - 1;
    const chunkSize = end - start + 1;
    const file = fs.createReadStream(filePath, { start, end });
    res.writeHead(206, { 'Content-Range': `bytes ${start}-${end}/${stat.size}`, 'Accept-Ranges': 'bytes', 'Content-Length': chunkSize, 'Content-Type': 'video/webm' });
    file.pipe(res);
  } else {
    res.writeHead(200, { 'Content-Length': stat.size, 'Content-Type': 'video/webm' });
    fs.createReadStream(filePath).pipe(res);
  }
});

// Save interviewer notes/summary to a recording
app.patch('/api/recordings/:id/notes', requireAuth, (req, res) => {
  const { notes } = req.body;
  // Allow editing if own recording OR in org position folder
  let rec = db.prepare('SELECT * FROM recordings WHERE id=? AND interviewer_id=?').get(req.params.id, req.session.userId);
  if (!rec) rec = db.prepare('SELECT r.* FROM recordings r JOIN job_positions p ON r.job_position_id=p.id WHERE r.id=? AND p.org_id=?').get(req.params.id, req.session.orgId);
  if (!rec) return res.status(403).json({ error: 'Access denied' });
  db.prepare('UPDATE recordings SET notes=? WHERE id=?').run(notes || '', req.params.id);
  res.json({ ok: true });
});

app.delete('/api/recordings/:id', requireAuth, (req, res) => {
  const rec = db.prepare('SELECT * FROM recordings WHERE id=? AND interviewer_id=?').get(req.params.id, req.session.userId);
  if (!rec) return res.status(404).json({ error: 'Not found' });
  try { if (fs.existsSync(rec.file_path)) fs.unlinkSync(rec.file_path); } catch(e) {}
  db.prepare('DELETE FROM recordings WHERE id=?').run(req.params.id);
  res.json({ ok: true });
});

app.delete('/api/sessions/:id', requireAuth, (req, res) => {
  const sess = db.prepare('SELECT * FROM sessions WHERE id=? AND interviewer_id=?').get(req.params.id, req.session.userId);
  if (!sess) return res.status(404).json({ error: 'Not found' });
  // Remove any recordings tied to this session (files + rows)
  try {
    const recs = db.prepare('SELECT * FROM recordings WHERE session_id=?').all(req.params.id);
    recs.forEach(function(rc){ try { if (rc.file_path && fs.existsSync(rc.file_path)) fs.unlinkSync(rc.file_path); } catch(e) {} });
    db.prepare('DELETE FROM recordings WHERE session_id=?').run(req.params.id);
  } catch(e) {}
  try { db.prepare('DELETE FROM flags WHERE session_id=?').run(req.params.id); } catch(e) {}
  db.prepare('DELETE FROM sessions WHERE id=?').run(req.params.id);
  res.json({ ok: true });
});

function streamVideo(req, res, filePath) {
  const stat = fs.statSync(filePath);
  const total = stat.size;
  const range = req.headers.range;
  if (range) {
    const parts = range.replace(/bytes=/, '').split('-');
    const start = parseInt(parts[0], 10);
    const end = parts[1] ? parseInt(parts[1], 10) : total - 1;
    res.writeHead(206, { 'Content-Range': `bytes ${start}-${end}/${total}`, 'Accept-Ranges': 'bytes', 'Content-Length': end - start + 1, 'Content-Type': 'video/webm' });
    fs.createReadStream(filePath, { start, end }).pipe(res);
  } else {
    res.writeHead(200, { 'Content-Length': total, 'Content-Type': 'video/webm', 'Accept-Ranges': 'bytes' });
    fs.createReadStream(filePath).pipe(res);
  }
}

