// List all members in the org
app.get('/api/org/members', requireAuth, (req, res) => {
  const members = db.prepare('SELECT id, name, email, role, created_at FROM users WHERE org_id=? ORDER BY role DESC, created_at ASC').all(req.session.orgId);
  res.json(members);
});

// Get org info (code + name)
app.get('/api/org/info', requireAuth, (req, res) => {
  const org = db.prepare('SELECT id, name, code FROM orgs WHERE id=?').get(req.session.orgId);
  res.json(org || { name: req.session.orgName, code: req.session.orgCode });
});

// Change a member's role (admin only)
app.patch('/api/org/members/:userId/role', requireAuth, (req, res) => {
  const _adminUser = db.prepare('SELECT role FROM users WHERE id=?').get(req.session.userId);
  if (!_adminUser || _adminUser.role !== 'admin') return res.status(403).json({ error: 'Admin only' });
  const { role } = req.body;
  if (!['admin','recruiter'].includes(role)) return res.status(400).json({ error: 'Invalid role' });
  // Can't demote yourself if you're the only admin
  if (req.params.userId === req.session.userId && role !== 'admin') {
    const adminCount = db.prepare("SELECT COUNT(*) as cnt FROM users WHERE org_id=? AND role='admin'").get(req.session.orgId).cnt;
    if (adminCount <= 1) return res.status(400).json({ error: 'Cannot remove the only admin' });
  }
  const user = db.prepare('SELECT * FROM users WHERE id=? AND org_id=?').get(req.params.userId, req.session.orgId);
  if (!user) return res.status(404).json({ error: 'Member not found' });
  db.prepare('UPDATE users SET role=? WHERE id=? AND org_id=?').run(role, req.params.userId, req.session.orgId);
  res.json({ ok: true });
});

// Remove a member from the org (admin only)
app.delete('/api/org/members/:userId', requireAuth, (req, res) => {
  const _adminUser = db.prepare('SELECT role FROM users WHERE id=?').get(req.session.userId);
  if (!_adminUser || _adminUser.role !== 'admin') return res.status(403).json({ error: 'Admin only' });
  if (req.params.userId === req.session.userId) return res.status(400).json({ error: 'Cannot remove yourself' });
  const user = db.prepare('SELECT * FROM users WHERE id=? AND org_id=?').get(req.params.userId, req.session.orgId);
  if (!user) return res.status(404).json({ error: 'Member not found' });
  db.prepare('DELETE FROM users WHERE id=? AND org_id=?').run(req.params.userId, req.session.orgId);
  res.json({ ok: true });
});

// Create an invite link token (admin only) - returns a one-time join token
app.post('/api/org/invite', requireAuth, (req, res) => {
  const _adminUser = db.prepare('SELECT role FROM users WHERE id=?').get(req.session.userId);
  if (!_adminUser || _adminUser.role !== 'admin') return res.status(403).json({ error: 'Admin only' });
  // Return the org code - that IS the invite mechanism
  const org = db.prepare('SELECT name, code FROM orgs WHERE id=?').get(req.session.orgId);
  const inviteUrl = '/join-company/' + (org ? org.code : req.session.orgCode);
  res.json({ ok: true, orgCode: org ? org.code : req.session.orgCode, inviteUrl, orgName: org ? org.name : req.session.orgName });
});


// Email invite - returns mailto link with session details
app.get('/api/sessions/:id/invite-email', requireAuth, (req, res) => {
  const s = db.prepare('SELECT * FROM sessions WHERE id=? AND org_id=?').get(req.params.id, req.session.orgId);
  if (!s) return res.status(404).json({ error: 'Session not found' });
  const joinUrl = (process.env.APP_URL || 'https://luca-proctor-fly-v1.fly.dev') + '/join/' + s.code;
  const subject = encodeURIComponent('Interview Invitation: ' + s.title);
  const body = encodeURIComponent(
    'You have been invited to an interview.\n\n' +
    'Session: ' + s.title + '\n' +
    'Candidate: ' + (s.candidate_name || 'You') + '\n\n' +
    'Join directly: ' + joinUrl + '\n\n' +
    'Or visit interviewmycandidate.com and enter code: ' + s.code + '\n\n' +
    (s.scheduled_at ? 'Scheduled: ' + new Date(s.scheduled_at * 1000).toLocaleString() + '\n\n' : '') +
    'Please join from a computer with camera and microphone enabled.'
  );
  res.json({ subject: decodeURIComponent(subject), body: decodeURIComponent(body), mailto: 'mailto:?subject=' + subject + '&body=' + body, joinUrl, code: s.code });
});

// JOB POSITIONS API
app.post('/api/positions', requireAuth, (req, res) => {
  const { title, description } = req.body;
  if (!title) return res.json({ error: 'Position title required' });
  const id = uuidv4();
  db.prepare('INSERT INTO job_positions (id,org_id,title,description,created_by) VALUES (?,?,?,?,?)').run(id, req.session.orgId, title, description||'', req.session.userId);
  res.json({ ok:true, id, title });
});
app.get('/api/positions', requireAuth, (req, res) => {
  const rows = db.prepare('SELECT p.*, u.name as created_by_name, (SELECT COUNT(*) FROM recordings r WHERE r.job_position_id=p.id) as recording_count FROM job_positions p LEFT JOIN users u ON p.created_by=u.id WHERE p.org_id=? ORDER BY p.created_at DESC').all(req.session.orgId);
  res.json(rows);
});
app.get('/api/positions/:id/recordings', requireAuth, (req, res) => {
  const pos = db.prepare('SELECT * FROM job_positions WHERE id=? AND org_id=?').get(req.params.id, req.session.orgId);
  if (!pos) return res.status(404).json({ error: 'Position not found' });
  const recs = db.prepare('SELECT r.*, r.notes, u.name as interviewer_name, s.title as session_title, s.candidate_name FROM recordings r LEFT JOIN users u ON r.interviewer_id=u.id LEFT JOIN sessions s ON r.session_id=s.id WHERE r.job_position_id=? ORDER BY r.created_at DESC').all(req.params.id);
  res.json({ position: pos, recordings: recs });
});
app.patch('/api/recordings/:id/position', requireAuth, (req, res) => {
  const { positionId } = req.body;
  const rec = db.prepare('SELECT * FROM recordings WHERE id=? AND interviewer_id=?').get(req.params.id, req.session.userId);
  if (!rec) return res.status(404).json({ error: 'Recording not found' });
  if (positionId) {
    const pos = db.prepare('SELECT id FROM job_positions WHERE id=? AND org_id=?').get(positionId, req.session.orgId);
    if (!pos) return res.json({ error: 'Position not found in your org' });
  }
  db.prepare('UPDATE recordings SET job_position_id=? WHERE id=?').run(positionId||null, req.params.id);
  res.json({ ok:true });
});
app.delete('/api/positions/:id', requireAuth, (req, res) => {
  const pos = db.prepare('SELECT * FROM job_positions WHERE id=? AND org_id=?').get(req.params.id, req.session.orgId);
  if (!pos) return res.status(404).json({ error: 'Not found' });
  db.prepare('UPDATE recordings SET job_position_id=NULL WHERE job_position_id=?').run(req.params.id);
  db.prepare('DELETE FROM job_positions WHERE id=?').run(req.params.id);
  res.json({ ok:true });
});

app.post('/api/teams', requireAuth, (req, res) => {
  const { name } = req.body;
  if (!name) return res.json({ error: 'Team name required' });
  const id = uuidv4();
  let code;
  do { code = uuidv4().slice(0, 8).toUpperCase(); } while (db.prepare('SELECT id FROM teams WHERE invite_code=?').get(code));
  db.prepare('INSERT INTO teams (id,name,org_id,owner_id,invite_code) VALUES (?,?,?,?,?)').run(id, name, req.session.orgId, req.session.userId, code);
  db.prepare('INSERT INTO team_members (team_id,user_id,role) VALUES (?,?,?)').run(id, req.session.userId, 'owner');
  res.json({ ok: true, id, inviteCode: code });
});

app.get('/api/teams', requireAuth, (req, res) => {
  const teams = db.prepare('SELECT t.* FROM teams t JOIN team_members tm ON t.id=tm.team_id WHERE tm.user_id=?').all(req.session.userId);
  res.json(teams.map(t => ({ ...t, members: db.prepare('SELECT u.id,u.name,u.email,tm.role FROM team_members tm JOIN users u ON tm.user_id=u.id WHERE tm.team_id=?').all(t.id) })));
});

app.post('/api/teams/join', requireAuth, (req, res) => {
  const { inviteCode } = req.body;
  const team = db.prepare('SELECT * FROM teams WHERE invite_code=?').get(inviteCode);
  if (!team) return res.json({ error: 'Invalid invite code' });
  if (db.prepare('SELECT * FROM team_members WHERE team_id=? AND user_id=?').get(team.id, req.session.userId)) return res.json({ error: 'Already a member' });
  db.prepare('INSERT INTO team_members (team_id,user_id) VALUES (?,?)').run(team.id, req.session.userId);
  res.json({ ok: true, teamName: team.name });
});

