// ------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------ SOCKET.IO ------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
const rooms = {};
io.on('connection', (socket) => {
  socket.on('join-room', ({ sessionId, role }) => {
    socket.join(sessionId);
    if (!rooms[sessionId]) rooms[sessionId] = {};
    rooms[sessionId][role] = socket.id;
    socket.data.sessionId = sessionId;
    socket.data.role = role;
    socket.to(sessionId).emit('peer-joined', { role });
    const others = Object.entries(rooms[sessionId]).filter(([r]) => r !== role);
    if (others.length) socket.emit('peer-already-present', { role: others[0][0] });
  });
  socket.on('webrtc-offer', ({ sessionId, offer }) => socket.to(sessionId).emit('webrtc-offer', { offer }));
  socket.on('webrtc-answer', ({ sessionId, answer }) => socket.to(sessionId).emit('webrtc-answer', { answer }));
  socket.on('webrtc-ice', ({ sessionId, candidate }) => socket.to(sessionId).emit('webrtc-ice', { candidate }));
  socket.on('screen-offer', ({ sessionId, offer }) => socket.to(sessionId).emit('screen-offer', { offer }));
  socket.on('screen-answer', ({ sessionId, answer }) => socket.to(sessionId).emit('screen-answer', { answer }));
  socket.on('screen-ice', ({ sessionId, candidate }) => socket.to(sessionId).emit('screen-ice', { candidate }));
  socket.on('screen-state', ({ sessionId, sharing }) => socket.to(sessionId).emit('screen-state', { sharing }));
  socket.on('next-question', ({ sessionId, qIdx }) => socket.to(sessionId).emit('next-question', { qIdx }));
  socket.on('session-ended', ({ sessionId }) => socket.to(sessionId).emit('session-ended'));
  socket.on('candidate-flag', ({ sessionId, flag }) => {
    socket.to(sessionId).emit('candidate-flag', flag);
    try {
      const id = uuidv4();
      db.prepare('INSERT INTO flags (id,session_id,time_offset,text,detail,severity) VALUES (?,?,?,?,?,?)').run(id, sessionId, flag.time || '00:00', flag.text, flag.detail || '', flag.severity || 'medium');
      // Weighted penalty system - calibrated so 0% = worst possible interview
      // Occasional mistakes don't destroy the score; sustained cheating does
      var flagText = (flag.text||'').toLowerCase();
      var penalty = 2; // default
      if(flagText.includes('background voice')||flagText.includes('coaching')) penalty = 6;
      else if(flagText.includes('multiple display')) penalty = 8;
      else if(flagText.includes('devtools')) penalty = 4;
      else if(flagText.includes('screen config')) penalty = 5;
      else if(flagText.includes('extended absence')) penalty = 5;
      else if(flagText.includes('tab switch')) penalty = 4;
      else if(flagText.includes('new tab')) penalty = 3;
      else if(flagText.includes('window switch')||flagText.includes('window blur')) penalty = 2;
      else if(flagText.includes('face not visible')) penalty = 2;
      else if(flagText.includes('gaze')||flagText.includes('eye')) penalty = 1;
      else if(flagText.includes('copy')||flagText.includes('paste')||flagText.includes('cut')) penalty = 2;
      else if(flagText.includes('shortcut')||flagText.includes('keyboard')) penalty = 1;
      else if(flagText.includes('right-click')||flagText.includes('right click')) penalty = 0.5;
      else if(flagText.includes('resize')) penalty = 0.5;
      else if(flag.severity === 'high') penalty = 4;
      else if(flag.severity === 'medium') penalty = 2;
      else if(flag.severity === 'low') penalty = 1;
      db.prepare('UPDATE sessions SET trust_score = MAX(0, trust_score - ?) WHERE id=?').run(penalty, sessionId);
    } catch(e) {}
  });
  // Relay lockout state to interviewer so they see the candidate is locked out
  socket.on('candidate-lockout', ({ sessionId, secondsLeft, violation }) => {
    socket.to(sessionId).emit('candidate-lockout', { secondsLeft, violation });
  });
  socket.on('candidate-lockout-end', ({ sessionId }) => {
    socket.to(sessionId).emit('candidate-lockout-end');
  });
  socket.on('recording-request', ({ sessionId }) => socket.to(sessionId).emit('recording-request'));
  socket.on('recording-consent', ({ sessionId, agreed }) => socket.to(sessionId).emit('recording-consent', { agreed: agreed }));
  socket.on('recording-started', ({ sessionId }) => socket.to(sessionId).emit('recording-started'));
  socket.on('recording-stopped', ({ sessionId }) => socket.to(sessionId).emit('recording-stopped'));

  socket.on('disconnect', () => {
    const { sessionId, role } = socket.data;
    if (sessionId && rooms[sessionId]) { delete rooms[sessionId][role]; socket.to(sessionId).emit('peer-left', { role }); }
  });
});


