// USER ACCOUNT SETTINGS
app.get('/api/auth/me/settings', requireAuth, (req, res) => {
  const user = db.prepare('SELECT id, name, email, role FROM users WHERE id=?').get(req.session.userId);
  if(!user) return res.status(404).json({ error: 'User not found' });
  res.json(user);
});

app.patch('/api/auth/me/settings', requireAuth, async (req, res) => {
  const { name, email, currentPassword, newPassword } = req.body;
  const bcrypt = require('bcryptjs');
  const user = db.prepare('SELECT * FROM users WHERE id=?').get(req.session.userId);
  if(!user) return res.status(404).json({ error: 'User not found' });
  
  // If changing email, check not already taken
  if(email && email !== user.email) {
    const existing = db.prepare('SELECT id FROM users WHERE email=? AND org_id=?').get(email.trim().toLowerCase(), user.org_id);
    if(existing) return res.json({ error: 'Email already in use' });
  }
  
  // If changing password, verify current password first
  if(newPassword) {
    if(!currentPassword) return res.json({ error: 'Current password required to set new password' });
    const valid = await bcrypt.compare(currentPassword, user.password);
    if(!valid) return res.json({ error: 'Current password is incorrect' });
    if(newPassword.length < 6) return res.json({ error: 'New password must be at least 6 characters' });
  }
  
  // Apply updates
  const newName = (name && name.trim()) || user.name;
  const newEmail = (email && email.trim().toLowerCase()) || user.email;
  const newHash = newPassword ? await bcrypt.hash(newPassword, 10) : user.password;
  
  db.prepare('UPDATE users SET name=?, email=?, password=? WHERE id=?').run(newName, newEmail, newHash, user.id);
  req.session.name = newName;
  
  res.json({ ok: true, name: newName, email: newEmail });
});

